@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="form-error">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            errorMessage = "Title and assignee are required.";
            return;
        }

        errorMessage = null;
        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column with header, task cards, and an add-task form toggle *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="() => OnMoveLeft.InvokeAsync(task.Id)"
                      OnMoveRight="() => OnMoveRight.InvokeAsync(task.Id)" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm OnSave="HandleTaskSave" OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskCreated.InvokeAsync(data);
        showForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <div class="board-loading">Loading tasks...</div>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="kanban-board">
        @foreach (var (status, index) in columns.Select((s, i) => (s, i)))
        {
            <KanbanColumn ColumnName="@status"
                          Tasks="GetFilteredTasksForColumn(status)"
                          ShowMoveLeft="index > 0"
                          ShowMoveRight="index < columns.Length - 1"
                          OnMoveLeft="id => MoveTask(id, columns[index - 1])"
                          OnMoveRight="id => MoveTask(id, columns[index + 1])"
                          OnTaskCreated="data => CreateTask(data, status)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private List<TaskItem> GetFilteredTasksForColumn(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

