@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="form-error">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            errorMessage = "Title and assignee are required.";
            return;
        }

        errorMessage = null;
        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

